% Faber2026 — CHIME/FRB–DSA-110 co-detected FRBs: dispersion & scattering budget
%
% Manuscript repo (Overleaf-synced). The analysis pipeline that produces the
% numbers and figures here is dsa110-FLITS, pinned as a git submodule under
% pipeline/ (see PIPELINE.md). Overleaf ignores the submodule and compiles
% the .tex / figures at the repo root.
\documentclass[twocolumn]{aastex631}

\usepackage{amsmath,amssymb}
\usepackage{graphicx}
\graphicspath{{figures/}}

\begin{document}

\title{Disentangling the Dispersion and Scattering Budgets of
CHIME/FRB--DSA-110 Co-detected Fast Radio Bursts}

% Author / affiliation block lives in auth.tex for reuse and clean diffs.
\input{auth.tex}

\begin{abstract}
We present a joint dispersion- and scattering-budget analysis of the twelve fast
radio bursts (FRBs) co-detected by CHIME/FRB ($0.4$--$0.8$\,GHz) and DSA-110
($\sim$1.4\,GHz) between 2022 February and 2024 February, spanning
$\mathrm{DM_{obs}}=262$--$960\,\mathrm{pc\,cm^{-3}}$. The $\sim$1\,GHz baseline
between the two detections breaks the degeneracy between the scattering time and
its spectral index that defeats any single-band fit, which we exploit with a
simultaneous two-band fit for a shared sightline pair
$(\tau_{1\,\mathrm{GHz}},\alpha)$. We decompose each observed DM into Milky-Way
(disk and halo), cosmological (Macquart), intervening circumgalactic, and host
contributions, sourcing the intervening term from a foreground-galaxy search that
returns 49 candidate systems along nine sightlines (29 confirmed foreground). An
intervening column is significant only for the three sightlines that pierce a
foreground galaxy's interior, where the host residual turns formally negative and
thereby bounds the circumgalactic model. For the eight sightlines with a
spectroscopic host redshift we measure band-restricted isotropic-equivalent
energies of $5\times10^{38}$--$1\times10^{41}\,\mathrm{erg}$. A
diffractive-scintillation excess of $\sim$7--11$\times$ the NE2025 Galactic floor
on the mid-latitude sightlines, robust across scattering-calibrated
electron-density models, indicates an extragalactic (host or intervening)
scattering screen rather than a Milky-Way origin. Finally, we show that unmodeled
temporal sub-components can bias the single-component scattering index by several
units, and an unphysical band-dependent pulse-broadening function by several
tenths; re-fitting the sample under a single physical pulse-broadening function
with per-band multiplicity, the well-constrained sightlines yield stable indices,
with the final per-sightline adjudication in progress.
\end{abstract}

\keywords{Radio transient sources (2008) --- Interstellar scattering (854)
--- Intergalactic medium (813) --- Circumgalactic medium (1879)}

